if (line !== "" && !lines.some(existingLine => existingLine.value === line)) {
    lines.push({ value: line, label: line });
}

// Add department if it doesn't already exist
if (department !== "" && !departments.some(existingDepartment => existingDepartment.value === department)) {
    departments.push({ value: department, label: department });
}

global.set('lines', lines, 'persistent');
global.set('departments', departments, 'persistent');

return msg;

